document.addEventListener("DOMContentLoaded",function(){"use strict";var e=document.getElementById("rand-min"),t=document.getElementById("rand-max"),n=document.getElementById("rand-count"),r=document.getElementById("rand-unique"),a=document.getElementById("rand-sort"),o=document.getElementById("generate-btn"),d=document.getElementById("reset-btn"),i=document.getElementById("copy-all-btn"),l=document.getElementById("result"),c=document.getElementById("result-summary"),u=document.getElementById("random-results"),s=[];function m(e,t){var n=t-e+1,r=new Uint32Array(1);return crypto.getRandomValues(r),e+r[0]%n}o.addEventListener("click",function(){var o=parseInt(e.value,10),d=parseInt(t.value,10),i=parseInt(n.value,10);if(isNaN(o)||isNaN(d))alert("最小値と最大値を正しく入力してください。");else if(o>d)alert("最小値は最大値以下にしてください。");else if(isNaN(i)||i<1||i>1e3)alert("生成個数は1〜1000の範囲で入力してください。");else{var v=d-o+1,g=r.checked;if(g&&i>v)alert("重複なしの場合、生成個数は範囲内の整数の数（"+v+"個）以下にしてください。");else{var f=[];if(g)for(var y={};f.length<i;){var p=m(o,d);y[p]||(y[p]=!0,f.push(p))}else for(var h=0;h<i;h++)f.push(m(o,d));a.checked&&f.sort(function(e,t){return e-t}),s=f,u.innerHTML="";for(var E=0;E<f.length;E++){var I=document.createElement("span");I.style.cssText="display:inline-block;padding:6px 12px;background:var(--color-bg-secondary);border:1px solid var(--color-border);border-radius:var(--radius-sm);font-size:0.95rem;font-weight:500;font-family:var(--font-mono);",I.textContent=f[E],u.appendChild(I)}c.textContent=i+"個の乱数（"+o+"〜"+d+"）",l.hidden=!1,l.scrollIntoView({behavior:"smooth"})}}}),i.addEventListener("click",function(){if(0!==s.length){var e=s.join(", ");navigator.clipboard&&navigator.clipboard.writeText&&navigator.clipboard.writeText(e).then(function(){var e=i.textContent;i.textContent="コピー済み",setTimeout(function(){i.textContent=e},1500)})}}),d.addEventListener("click",function(){e.value="1",t.value="100",n.value="10",r.checked=!1,a.checked=!1,u.innerHTML="",c.textContent="",l.hidden=!0,s=[]})});